import React, { useState, useCallback, useMemo } from 'react';
import { AppMode, AppSettings } from './types';
import { DEFAULT_SETTINGS } from './constants';
import { CountdownView } from './components/CountdownView';
import { SlideshowView } from './components/SlideshowView';
import { SettingsView } from './components/SettingsView';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.COUNTDOWN);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);

  // Helper to calculate the next occurrence of the configured day/time
  const getNextTargetDate = useCallback((s: AppSettings) => {
    const now = new Date();
    const target = new Date();

    target.setHours(s.autoStartHour, s.autoStartMinute, 0, 0);

    // Calculate days until next occurrence
    // current: 0(Sun) - 6(Sat)
    // target: s.autoStartDay
    const currentDay = now.getDay();
    let daysUntil = (s.autoStartDay - currentDay + 7) % 7;

    // If it's today but the time has passed, move to next week
    if (daysUntil === 0 && target <= now) {
      daysUntil = 7;
    }

    target.setDate(now.getDate() + daysUntil);
    return target;
  }, []);

  const nextTargetDate = useMemo(() => getNextTargetDate(settings), [settings, getNextTargetDate]);

  const handleCountdownComplete = useCallback(() => {
    setMode(AppMode.SLIDESHOW);
  }, []);

  const handleReturnToCountdown = useCallback(() => {
    setMode(AppMode.COUNTDOWN);
  }, []);

  const handleOpenSettings = useCallback(() => {
    setMode(AppMode.SETTINGS);
  }, []);

  const handleSaveSettings = useCallback((newSettings: AppSettings) => {
    setSettings(newSettings);
    setMode(AppMode.COUNTDOWN);
  }, []);

  const handleCancelSettings = useCallback(() => {
    setMode(AppMode.COUNTDOWN);
  }, []);

  return (
    <div className="w-full h-full relative">

      {mode === AppMode.SETTINGS && (
        <SettingsView 
          currentSettings={settings}
          onSave={handleSaveSettings}
          onCancel={handleCancelSettings}
        />
      )}

      {mode === AppMode.COUNTDOWN && (
        <CountdownView 
          targetDate={nextTargetDate}
          onComplete={handleCountdownComplete}
          onOpenSettings={handleOpenSettings}
        />
      )}

      {mode === AppMode.SLIDESHOW && (
        <SlideshowView onExit={handleReturnToCountdown} settings={settings} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';

interface CountdownViewProps {
  onComplete: () => void;
  onOpenSettings: () => void;
  targetDate: Date;
}

// Awana Colors for particles
const PARTICLE_COLORS = ['bg-red-600', 'bg-blue-600', 'bg-green-600', 'bg-yellow-500'];

interface Particle {
  id: number;
  left: string;
  size: string;
  color: string;
  duration: string;
  delay: string;
}

export const CountdownView: React.FC<CountdownViewProps> = ({ onComplete, onOpenSettings, targetDate }) => {
  const [timeLeft, setTimeLeft] = useState(0);

  // Generate particles only once on mount
  const particles = useMemo(() => {
    const items: Particle[] = [];
    for (let i = 0; i < 30; i++) {
      items.push({
        id: i,
        left: `${Math.random() * 100}%`,
        size: `${Math.random() * 3 + 1}rem`, // 1rem to 4rem
        color: PARTICLE_COLORS[Math.floor(Math.random() * PARTICLE_COLORS.length)],
        duration: `${Math.random() * 10 + 10}s`, // 10s to 20s duration
        delay: `-${Math.random() * 20}s`, // Negative delay to start mid-animation
      });
    }
    return items;
  }, []);

  useEffect(() => {
    const calculateTimeLeft = () => {
      const now = new Date().getTime();
      const distance = targetDate.getTime() - now;
      if (distance <= 0) {
        onComplete();
        return 0;
      }
      return Math.floor(distance / 1000);
    };

    // Initial check
    setTimeLeft(calculateTimeLeft());

    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, [targetDate, onComplete]);

  // Keyboard support for skipping
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      switch (event.code) {
        case 'Space':
        case 'ArrowRight':
        case 'PageDown':
          event.preventDefault();
          onComplete(); // Skip timer
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onComplete]);

  // Formatting Logic
  const days = Math.floor(timeLeft / (3600 * 24));
  const hours = Math.floor((timeLeft % (3600 * 24)) / 3600);
  const minutes = Math.floor((timeLeft % 3600) / 60);
  const seconds = timeLeft % 60;

  let formattedTime = '';
  let isLongFormat = false;

  if (days > 0) {
    formattedTime = `${days}d ${hours}h ${minutes}m`;
    isLongFormat = true;
  } else if (hours > 0) {
    formattedTime = `${hours}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  } else {
    formattedTime = `${minutes}:${seconds.toString().padStart(2, '0')}`;
  }

  // Calculate color urgency
  const isUrgent = timeLeft < 60 && timeLeft > 0;

  return (
    <div className="w-full h-full flex flex-col items-center justify-center bg-black relative overflow-hidden animate-fade-in">

       {/* Settings Button (Top Right) */}
       <button 
        onClick={onOpenSettings}
        className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors p-2 z-50"
        title="Settings"
      >
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
        </svg>
      </button>

      {/* Background Particles Layer */}
      <div className="absolute inset-0 pointer-events-none">
        {particles.map((p) => (
          <div
            key={p.id}
            className={`rounded-full animate-float ${p.color} blur-sm`}
            style={{
              left: p.left,
              width: p.size,
              height: p.size,
              animationDuration: p.duration,
              animationDelay: p.delay,
            }}
          />
        ))}
      </div>

      {/* Content Layer - Full screen centered */}
      <div className="z-10 w-full h-full flex flex-col items-center justify-center">

        <h2 className="text-4xl text-gray-400 font-bold mb-8 uppercase tracking-widest">
          Club Starts In
        </h2>

        <div 
            className="relative w-full flex justify-center items-center cursor-pointer group"
            onClick={onComplete}
            title="Click to skip timer"
        >
            {/* Massive time display */}
            <h1 className={`${isLongFormat ? 'text-[12vw]' : 'text-[25vw]'} leading-none font-bold tabular-nums drop-shadow-2xl transition-colors duration-500 ${isUrgent ? 'text-red-500' : 'text-white'} group-hover:text-gray-200`}>
            {formattedTime}
            </h1>
            <div className="absolute bottom-0 opacity-0 group-hover:opacity-100 text-sm text-gray-500 font-semibold uppercase tracking-widest transition-opacity">
                Click to Skip
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { SLIDES, GAME_SLIDES } from '../constants';
import { Slide } from './Slide';
import { AppSettings, SlideContent } from '../types';

interface SlideshowViewProps {
  onExit: () => void;
  settings: AppSettings;
}

export const SlideshowView: React.FC<SlideshowViewProps> = ({ onExit, settings }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isExiting, setIsExiting] = useState(false);

  // Transition duration in ms - should match the CSS duration in Slide.tsx
  const TRANSITION_DURATION = 500;

  // Compute the full list of slides: [Default] -> [Settings Final] -> [Game Slides]
  const activeSlides = useMemo(() => {
    const slides: SlideContent[] = [...SLIDES];

    // Create Final Slide based on settings
    const finalSlide: SlideContent = {
      id: 999,
      title: '', // Usually hidden if empty
      body: '',
      bgColorClass: 'bg-black',
      accentColorClass: 'text-white',
    };

    if (settings.finalSlideType === 'text') {
      finalSlide.body = settings.finalSlideContent || 'Thank You!';
    } else if (settings.finalSlideType === 'image') {
      finalSlide.imageUrl = settings.finalSlideContent;
    }
    // If 'black', body and imageUrl remain undefined/empty, rendering a black screen

    slides.push(finalSlide);

    // Append Time-Based Game Slides
    slides.push(...GAME_SLIDES);

    return slides;
  }, [settings]);

  const changeSlide = useCallback((newIndex: number) => {
    // 1. Start Exit Animation
    setIsExiting(true);

    // 2. Wait for animation to finish, then swap content and start Enter Animation
    setTimeout(() => {
      setCurrentIndex(newIndex);
      setIsExiting(false);
    }, TRANSITION_DURATION);
  }, []);

  const goToNext = useCallback(() => {
    if (currentIndex < activeSlides.length - 1 && !isExiting) {
      changeSlide(currentIndex + 1);
    }
  }, [currentIndex, isExiting, changeSlide, activeSlides.length]);

  const goToPrev = useCallback(() => {
    if (currentIndex > 0 && !isExiting) {
      changeSlide(currentIndex - 1);
    }
  }, [currentIndex, isExiting, changeSlide]);

  // Automated Schedule Navigation
  useEffect(() => {
    const checkSchedule = () => {
        const now = new Date();
        const currentHour = now.getHours();
        const currentMinute = now.getMinutes();

        // Check if we need to auto-jump to a scheduled slide
        activeSlides.forEach((slide, index) => {
            if (slide.schedule) {
                // Check if current time matches the scheduled start time
                if (slide.schedule.startHour === currentHour && slide.schedule.startMinute === currentMinute) {
                    // Only jump if we are not already on this slide
                    // Also check seconds to prevent continuous re-triggering (only trigger at :00)
                    if (index !== currentIndex && now.getSeconds() === 0) {
                        changeSlide(index);
                    }
                }
            }
        });
    };

    const timer = setInterval(checkSchedule, 1000);
    return () => clearInterval(timer);
  }, [activeSlides, currentIndex, changeSlide]);

  // Auto-advance logic for slides with specific duration
  useEffect(() => {
    const currentSlide = activeSlides[currentIndex];
    if (currentSlide.duration && !isExiting) {
      const durationMs = currentSlide.duration * 1000;
      const timer = setTimeout(() => {
        if (currentIndex < activeSlides.length - 1) {
            goToNext();
        }
      }, durationMs);
      return () => clearTimeout(timer);
    }
  }, [currentIndex, activeSlides, isExiting, goToNext]);


  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      // Block input during transition
      if (isExiting) return;

      switch (event.code) {
        case 'Space':
        case 'ArrowRight':
        case 'PageDown':
          event.preventDefault(); // Prevent scrolling
          goToNext();
          break;
        case 'ArrowLeft':
        case 'PageUp':
          event.preventDefault();
          goToPrev();
          break;
        case 'Escape':
            if(confirm("Exit Presentation Mode?")) {
                onExit();
            }
            break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [goToNext, goToPrev, onExit, isExiting]);

  return (
    <div className="w-full h-full relative group bg-black">
      <Slide 
        content={activeSlides[currentIndex]} 
        isExiting={isExiting} 
        onNext={goToNext}
      />

      {/* Navigation Hints (Hidden by default, hover to see) */}
      <div className="fixed bottom-8 right-8 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-50">
        <button 
          onClick={goToPrev}
          disabled={currentIndex === 0 || isExiting}
          className="p-3 bg-gray-800/50 rounded-full text-white disabled:opacity-30 hover:bg-gray-700 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <button 
          onClick={goToNext}
          disabled={currentIndex === activeSlides.length - 1 || isExiting}
          className="p-3 bg-gray-800/50 rounded-full text-white disabled:opacity-30 hover:bg-gray-700 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppSettings, FinalSlideType } from '../types';

interface SettingsViewProps {
  currentSettings: AppSettings;
  onSave: (settings: AppSettings) => void;
  onCancel: () => void;
}

const DAYS_OF_WEEK = [
  'Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'
];

export const SettingsView: React.FC<SettingsViewProps> = ({ currentSettings, onSave, onCancel }) => {
  const [formData, setFormData] = useState<AppSettings>(currentSettings);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    if (name === 'autoStartDay' || name === 'autoStartHour' || name === 'autoStartMinute') {
        setFormData(prev => ({
          ...prev,
          [name]: parseInt(value, 10)
        }));
    } else {
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          finalSlideContent: reader.result as string
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  return (
    <div className="w-full h-full flex flex-col items-center justify-center bg-black text-white p-8 overflow-y-auto">
      <div className="max-w-xl w-full bg-gray-900 p-8 rounded-xl shadow-2xl border border-gray-800 my-8">
        <h2 className="text-3xl font-bold mb-6 text-center text-yellow-400">Presentation Settings</h2>

        <form onSubmit={handleSubmit} className="space-y-6">

          <div className="border-b border-gray-800 pb-6">
            <h3 className="text-xl font-semibold mb-4 text-blue-300">Countdown Target</h3>
            <p className="text-sm text-gray-400 mb-4">Set the day and time for your club. The timer will always count down to the next occurrence of this time.</p>

            {/* Day of Week */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-300 mb-1">Day of Week</label>
              <select
                name="autoStartDay"
                value={formData.autoStartDay}
                onChange={handleChange}
                className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
              >
                {DAYS_OF_WEEK.map((day, index) => (
                  <option key={index} value={index}>{day}</option>
                ))}
              </select>
            </div>

            {/* Time */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Hour (0-23)</label>
                <input
                  type="number"
                  name="autoStartHour"
                  min="0"
                  max="23"
                  value={formData.autoStartHour}
                  onChange={handleChange}
                  className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
                />
                <p className="text-xs text-gray-500 mt-1">18 = 6 PM</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Minute (0-59)</label>
                <input
                  type="number"
                  name="autoStartMinute"
                  min="0"
                  max="59"
                  value={formData.autoStartMinute}
                  onChange={handleChange}
                  className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
                />
              </div>
            </div>
          </div>

          <div className="pt-2">
            <h3 className="text-xl font-semibold mb-4 text-green-400">Final Slide Configuration</h3>

            <div className="mb-4">
                <label className="block text-sm font-medium text-gray-300 mb-1">Slide Type</label>
                <select
                    name="finalSlideType"
                    value={formData.finalSlideType}
                    onChange={handleChange}
                    className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
                >
                    <option value="black">Black Screen (Default)</option>
                    <option value="text">Custom Text</option>
                    <option value="image">Custom Image</option>
                </select>
            </div>

            {formData.finalSlideType === 'text' && (
                <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Text Content</label>
                    <textarea
                        name="finalSlideContent"
                        rows={3}
                        value={formData.finalSlideContent}
                        onChange={handleChange}
                        className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
                        placeholder="Enter text to display..."
                    />
                </div>
            )}

            {formData.finalSlideType === 'image' && (
                <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Upload Image</label>
                    <input 
                        type="file" 
                        accept="image/*"
                        onChange={handleImageUpload}
                        className="w-full bg-black border border-gray-700 rounded-md p-3 text-white focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    {formData.finalSlideContent && (
                        <div className="mt-2">
                             <p className="text-xs text-green-500 mb-1">Preview:</p>
                             <img src={formData.finalSlideContent} alt="Preview" className="h-20 object-contain border border-gray-700" />
                        </div>
                    )}
                </div>
            )}

          </div>

          <div className="flex gap-4 pt-4">
            <button
              type="button"
              onClick={onCancel}
              className="flex-1 px-4 py-3 bg-gray-800 hover:bg-gray-700 text-white rounded-lg transition-colors font-medium"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors font-bold shadow-lg"
            >
              Save Settings
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

