interface SettingsViewProps {
  currentSettings: AppSettings;
  onSave: (settings: AppSettings) => void;
  onCancel: () => void;
}

const DAYS_OF_WEEK = [
  'Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'
];

export const SettingsView: React.FC<SettingsViewProps> = ({ currentSettings, onSave, onCancel }) => {
  const [formData, setFormData] = useState<AppSettings>(currentSettings);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    if (name === 'autoStartDay' || name === 'autoStartHour' || name === 'autoStartMinute' || name === 'countdownDurationMinutes') {
        setFormData(prev => ({
          ...prev,
          [name]: parseInt(value, 10)
        }));
    } else {
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          finalSlideContent: reader.result as string
        }));
      };
      reader.readAsDataURL(file);
